<?require("../Cart.php");Brand();DBInfo();Root();commonHeader("$Company","Update An Item");mysql_connect("$DBHost","$DBUser","$DBPass");$result=mysql("$DBName","SELECT * FROM AItems WHERE ItemID = '$ItemID'");while($row=mysql_fetch_row($result)) {$IS=$row[0];$IN=$row[1];$ID=$row[2];$IC=$row[3];$Ca=$row[4];$SC=$row[5];$II=$row[6];}blueFont("Arial","Type the new data into the boxes, and then SUBMIT!<br><br>");echo "<TABLE BORDER=\"0\" CELLPADDING=\"10\" CELLSPACING=\"10\"><TR>";echo "<FORM ACTION=\"./updateItemResponse.php\" METHOD=\"POST\">";echo "<tr><td>";blueFont("Arial","Item ID (SKU)<br>");echo "<input type='text' name=\"ItemSKU\" size=\"40\" value=\"$IS\"></td></tr><tr><td>";blueFont("Arial","Item Name<br>");echo "<input type=\"text\" name=\"ItemName\" size=\"40\" value=\"$IN\"></td></tr>";echo "<tr><td>";blueFont("Arial","Item Cost<br>");if ($IC == "0.00") {$IC = ""; }echo "<input type=\"text\" name=\"ItemCost\" size=\"40\" value=\"$IC\"></td></tr><tr><td>";blueFont("Arial","Shipping Cost<br>");if ($SC == "0.00") {$SC = ""; }echo "<input type=\"text\" name=\"ShippingCost\" size=\"40\" value=\"$SC\"></td></tr>";echo "<tr><td>";blueFont("Arial","Select A Category<br>");echo "<select name=\"Category\" size=\"1\">";$result=mysql("$DBName","SELECT * FROM ACategory WHERE CategoryID='$Ca'");while ($row = mysql_fetch_row($result)) {echo "<option value=\"$row[1]\"> $row[0] </option>"; }echo "<option value=\"\"> ---------- </option>";mysql_connect("$DBHost","$DBUser","$DBPass");$result=mysql("$DBName","SELECT * FROM ACategory ORDER BY Category");while ($row = mysql_fetch_row($result)) {echo "<option value=\"$row[1]\"> $row[0] </option>";}echo "</select></td></tr>";echo "<tr><td colspan='2'>";blueFont("Arial","ItemDescription<br>");$ID=ereg_replace("\"","&quot;",$ID);echo "<textarea name=\"ItemDescription\" rows=\"10\" cols=\"50\" wrap>$ID</textarea></td></tr>";echo "<input type=\"hidden\" name=\"ItemID\" value=\"$II\">";echo "<tr><td colspan=\"2\" align=\"center\"><INPUT TYPE=\"submit\" NAME=\"Submit\" VALUE=\"Submit\"></form></TABLE>";adminFooter($Relative);?>